-- 6. Herne Bay × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'herne-bay',
  'Social media is where Herne Bay''s community actually lives online. The local Facebook groups covering Herne Bay events, recommendations, and news are among the most active in the Canterbury district, and Instagram accounts showcasing the seafront, Reculver Towers sunsets, and the Clock Tower regularly generate significant engagement. Yet most Herne Bay businesses have social profiles that were set up hastily and have not been updated to reflect current offerings, branding, or business information. A cafe near Hampton Pier with blurry logo images and an outdated menu. A tradesperson whose Facebook page still lists a phone number they changed two years ago. Your social media profiles are often the first thing a potential customer sees, and in a community as socially connected as Herne Bay, a poorly set up profile does not just look unprofessional; it actively costs you referral business when someone asks for recommendations in the local groups.',
  'Herne Bay''s social media landscape is dominated by community Facebook groups where residents recommend businesses, share events at Memorial Park and the King''s Hall, and discuss the seafront regeneration. Instagram engagement is strong around coastal photography, with the Clock Tower, Reculver Towers, and beach huts generating consistent visual content opportunities. The town''s demographic mix means both Facebook and Instagram are essential, with the older residential population active on Facebook and younger families engaging across both platforms.',
  'Social media setup quality among Herne Bay businesses is generally poor. Profile images are often low-resolution logos or personal photos, business information is frequently outdated, and there is little consistency between a business''s website branding and their social presence. A handful of seafront hospitality businesses maintain well-curated Instagram profiles that demonstrate the commercial impact of getting social media right, but these are the exception.',
  'We set up Herne Bay business social media profiles as proper commercial tools rather than afterthoughts. Every profile receives professional branded imagery, complete and accurate business information, optimised descriptions targeting Herne Bay and surrounding areas, and a content framework that makes ongoing posting manageable. We ensure your profiles are positioned to capture the referral traffic that flows through Herne Bay''s active community groups.',
  '{"population": 38000, "district": "Canterbury", "key_areas": ["High Street", "Seafront", "Hampton Pier", "Clock Tower area"], "social_landscape": "very active community Facebook groups, growing Instagram engagement"}',
  '[{"title": "Herne Bay social profiles that embarrass the business they represent", "description": "A skilled Herne Bay business owner gets recommended in a community Facebook group. The potential customer clicks through to a profile with a pixelated logo, a cover image from three years ago, and business hours that are wrong. They close the page and scroll to the next recommendation. This happens in Herne Bay every single day."}, {"title": "Inconsistent branding between Herne Bay business website and social media", "description": "A Herne Bay business has invested in a decent website, but their Facebook page uses a different logo, different colours, and different messaging. When customers encounter the brand across multiple touchpoints, the inconsistency raises subconscious doubts about professionalism and reliability."}, {"title": "Missing platforms meaning missing Herne Bay customer segments entirely", "description": "A Herne Bay business with only a Facebook page is invisible to the younger families and visitors who discover businesses through Instagram. A business on Instagram only is missing the older residential community that relies on Facebook recommendations. Without proper setup across the relevant platforms, entire customer segments are unreachable."}]',
  '[{"title": "Professional Herne Bay social media profile setup across all relevant platforms", "description": "We set up or overhaul your Facebook, Instagram, and Google Business profiles with professional branded imagery, complete business information, and optimised descriptions that reference Herne Bay, the High Street, seafront, and surrounding areas. Every profile is consistent with your brand identity and ready to generate business."}, {"title": "Content framework designed for Herne Bay''s community dynamics", "description": "We create a content plan that aligns with Herne Bay''s social rhythm: Memorial Park events, seafront seasonal changes, community group engagement opportunities, and local partnerships. This framework makes consistent posting manageable and ensures your content resonates with the Herne Bay audience."}, {"title": "Community group integration strategy for Herne Bay businesses", "description": "We develop guidelines for engaging authentically in Herne Bay''s active Facebook community groups, where much of the town''s recommendation economy operates. This includes profile positioning that builds trust when group members click through to your business page after seeing a recommendation."}]',
  '[{"question": "Which social media platforms matter most for Herne Bay businesses?", "answer": "Facebook and Instagram are essential for most Herne Bay businesses. Facebook drives the recommendation economy through active community groups, while Instagram captures the visual appeal of the seafront and attracts visitors. Google Business Profile is critical for search visibility. We assess your specific business and customer base to prioritise correctly."}, {"question": "Can you help me get noticed in Herne Bay Facebook groups?", "answer": "We set up your profiles so that when you are recommended in Herne Bay community groups, the click-through experience is professional and compelling. We also provide guidelines for authentic group engagement that builds your reputation without being overtly promotional, which Herne Bay community groups react negatively to."}, {"question": "How long does social media setup take for a Herne Bay business?", "answer": "A complete social media setup covering Facebook, Instagram, and Google Business Profile typically takes five to seven working days. This includes professional imagery, optimised descriptions, complete business information, branded templates, and a content framework tailored to the Herne Bay market."}, {"question": "Do you manage ongoing social media posting for Herne Bay businesses?", "answer": "Our core service is professional setup and content framework creation. We also offer ongoing management for Herne Bay businesses that prefer to hand off posting entirely. However, many of our clients find that with the framework and templates we provide, managing their own content becomes straightforward and sustainable."}]',
  'trust'
)
